    37→	constructor(
    38→		extHostContext: IExtHostContext,
    39→		@IFileService private readonly _fileService: IFileService,
    40→		@IWorkingCopyFileService workingCopyFileService: IWorkingCopyFileService,
    41→		@IBulkEditService bulkEditService: IBulkEditService,
    42→		@IProgressService progressService: IProgressService,
    43→		@IDialogService dialogService: IDialogService,
    44→		@IStorageService storageService: IStorageService,
    45→		@ILogService logService: ILogService,
    46→		@IEnvironmentService envService: IEnvironmentService,
    47→		@IUriIdentityService uriIdentService: IUriIdentityService,
    48→		@ILogService private readonly _logService: ILogService,
    49→	) {
    50→		this._proxy = extHostContext.getProxy(ExtHostContext.ExtHostFileSystemEventService);
    51→
    52→		this._listener.add(_fileService.onDidFilesChange(event => {
    53→			this._proxy.$onFileEvent({
    54→				created: event.rawAdded,
    55→				changed: event.rawUpdated,
    56→				deleted: event.rawDeleted
    57→			});
    58→		}));
    59→
    60→		const that = this;
    61→		const fileOperationParticipant = new class implements IWorkingCopyFileOperationParticipant {
    62→			async participate(files: SourceTargetPair[], operation: FileOperation, undoInfo: IFileOperationUndoRedoInfo | undefined, timeout: number, token: CancellationToken) {
    63→				if (undoInfo?.isUndoing) {
    64→					return;
    65→				}
    66→
    67→				const cts = new CancellationTokenSource(token);
    68→				const timer = setTimeout(() => cts.cancel(), timeout);
    69→
    70→				const data = await progressService.withProgress({
    71→					location: ProgressLocation.Notification,
    72→					title: this._progressLabel(operation),
    73→					cancellable: true,
    74→					delay: Math.min(timeout / 2, 3000)
    75→				}, () => {
    76→					// race extension host event delivery against timeout AND user-cancel
    77→					const onWillEvent = that._proxy.$onWillRunFileOperation(operation, files, timeout, cts.token);
    78→					return raceCancellation(onWillEvent, cts.token);
    79→				}, () => {
    80→					// user-cancel
    81→					cts.cancel();
    82→
    83→				}).finally(() => {
    84→					cts.dispose();
    85→					clearTimeout(timer);
    86→				});
    87→
    88→				if (!data || data.edit.edits.length === 0) {
    89→					// cancelled, no reply, or no edits
    90→					return;
    91→				}
    92→
    93→				const needsConfirmation = data.edit.edits.some(edit => edit.metadata?.needsConfirmation);
    94→				let showPreview = storageService.getBoolean(MainThreadFileSystemEventService.MementoKeyAdditionalEdits, StorageScope.PROFILE);
    95→
    96→				if (envService.extensionTestsLocationURI) {
    97→					// don't show dialog in tests
    98→					showPreview = false;
    99→				}
   100→
   101→				if (showPreview === undefined) {
   102→					// show a user facing message
   103→
   104→					let message: string;
   105→					if (data.extensionNames.length === 1) {
   106→						if (operation === FileOperation.CREATE) {
   107→							message = localize('ask.1.create', "Extension '{0}' wants to make refactoring changes with this file creation", data.extensionNames[0]);
   108→						} else if (operation === FileOperation.COPY) {
   109→							message = localize('ask.1.copy', "Extension '{0}' wants to make refactoring changes with this file copy", data.extensionNames[0]);
   110→						} else if (operation === FileOperation.MOVE) {
   111→							message = localize('ask.1.move', "Extension '{0}' wants to make refactoring changes with this file move", data.extensionNames[0]);
   112→						} else /* if (operation === FileOperation.DELETE) */ {
   113→							message = localize('ask.1.delete', "Extension '{0}' wants to make refactoring changes with this file deletion", data.extensionNames[0]);
   114→						}
   115→					} else {
   116→						if (operation === FileOperation.CREATE) {
   117→							message = localize({ key: 'ask.N.create', comment: ['{0} is a number, e.g "3 extensions want..."'] }, "{0} extensions want to make refactoring changes with this file creation", data.extensionNames.length);
   118→						} else if (operation === FileOperation.COPY) {
   119→							message = localize({ key: 'ask.N.copy', comment: ['{0} is a number, e.g "3 extensions want..."'] }, "{0} extensions want to make refactoring changes with this file copy", data.extensionNames.length);
   120→						} else if (operation === FileOperation.MOVE) {
   121→							message = localize({ key: 'ask.N.move', comment: ['{0} is a number, e.g "3 extensions want..."'] }, "{0} extensions want to make refactoring changes with this file move", data.extensionNames.length);
   122→						} else /* if (operation === FileOperation.DELETE) */ {
   123→							message = localize({ key: 'ask.N.delete', comment: ['{0} is a number, e.g "3 extensions want..."'] }, "{0} extensions want to make refactoring changes with this file deletion", data.extensionNames.length);
   124→						}
   125→					}
   126→
   127→					if (needsConfirmation) {
   128→						// edit which needs confirmation -> always show dialog
   129→						const { confirmed } = await dialogService.confirm({
   130→							type: Severity.Info,
   131→							message,
   132→							primaryButton: localize('preview', "Show &&Preview"),
   133→							cancelButton: localize('cancel', "Skip Changes")
   134→						});
   135→						showPreview = true;
   136→						if (!confirmed) {
   137→							// no changes wanted
   138→							return;
   139→						}
   140→					} else {
   141→						// choice
   142→						enum Choice {
   143→							OK = 0,
   144→							Preview = 1,
   145→							Cancel = 2
   146→						}
   147→						const { result, checkboxChecked } = await dialogService.prompt<Choice>({
   148→							type: Severity.Info,
   149→							message,
   150→							buttons: [
   151→								{
   152→									label: localize({ key: 'ok', comment: ['&& denotes a mnemonic'] }, "&&OK"),
   153→									run: () => Choice.OK
   154→								},
   155→								{
   156→									label: localize({ key: 'preview', comment: ['&& denotes a mnemonic'] }, "Show &&Preview"),
   157→									run: () => Choice.Preview
   158→								}
   159→							],
   160→							cancelButton: {
   161→								label: localize('cancel', "Skip Changes"),
   162→								run: () => Choice.Cancel
   163→							},
   164→							checkbox: { label: localize('again', "Do not ask me again") }
   165→						});
   166→						if (result === Choice.Cancel) {
   167→							// no changes wanted, don't persist cancel option
   168→							return;
   169→						}
   170→						showPreview = result === Choice.Preview;
   171→						if (checkboxChecked) {
   172→							storageService.store(MainThreadFileSystemEventService.MementoKeyAdditionalEdits, showPreview, StorageScope.PROFILE, StorageTarget.USER);
   173→						}
   174→					}
   175→				}
   176→
   177→				logService.info('[onWill-handler] applying additional workspace edit from extensions', data.extensionNames);
   178→
   179→				await bulkEditService.apply(
   180→					reviveWorkspaceEditDto(data.edit, uriIdentService),
   181→					{ undoRedoGroupId: undoInfo?.undoRedoGroupId, showPreview }
   182→				);
   183→			}
