   185→			private _progressLabel(operation: FileOperation): string {
   186→				switch (operation) {
   187→					case FileOperation.CREATE:
   188→						return localize('msg-create', "Running 'File Create' participants...");
   189→					case FileOperation.MOVE:
   190→						return localize('msg-rename', "Running 'File Rename' participants...");
   191→					case FileOperation.COPY:
   192→						return localize('msg-copy', "Running 'File Copy' participants...");
   193→					case FileOperation.DELETE:
   194→						return localize('msg-delete', "Running 'File Delete' participants...");
   195→					case FileOperation.WRITE:
   196→						return localize('msg-write', "Running 'File Write' participants...");
   197→				}
   198→			}
   199→		};
   200→
   201→		// BEFORE file operation
   202→		this._listener.add(workingCopyFileService.addFileOperationParticipant(fileOperationParticipant));
   203→
   204→		// AFTER file operation
   205→		this._listener.add(workingCopyFileService.onDidRunWorkingCopyFileOperation(e => this._proxy.$onDidRunFileOperation(e.operation, e.files)));
   206→	}
