   208→	async $watch(extensionId: string, session: number, resource: UriComponents, unvalidatedOpts: IWatchOptions, correlate: boolean): Promise<void> {
   209→		const uri = URI.revive(resource);
   210→
   211→		const opts: IWatchOptions = {
   212→			...unvalidatedOpts
   213→		};
   214→
   215→		// Convert a recursive watcher to a flat watcher if the path
   216→		// turns out to not be a folder. Recursive watching is only
   217→		// possible on folders, so we help all file watchers by checking
   218→		// early.
   219→		if (opts.recursive) {
   220→			try {
   221→				const stat = await this._fileService.stat(uri);
   222→				if (!stat.isDirectory) {
   223→					opts.recursive = false;
   224→				}
   225→			} catch (error) {
   226→				// ignore
   227→			}
   228→		}
   229→
   230→		// Correlated file watching: use an exclusive `createWatcher()`
   231→		if (correlate) {
   232→			this._logService.trace(`MainThreadFileSystemEventService#$watch(): request to start watching correlated (extension: ${extensionId}, path: ${uri.toString(true)}, recursive: ${opts.recursive}, session: ${session}, excludes: ${JSON.stringify(opts.excludes)}, includes: ${JSON.stringify(opts.includes)})`);
   233→
   234→			const watcherDisposables = new DisposableStore();
   235→			const subscription = watcherDisposables.add(this._fileService.createWatcher(uri, opts));
   236→			watcherDisposables.add(subscription.onDidChange(event => {
   237→				this._proxy.$onFileEvent({
   238→					session,
   239→					created: event.rawAdded,
   240→					changed: event.rawUpdated,
   241→					deleted: event.rawDeleted
   242→				});
   243→			}));
   244→
   245→			this._watches.set(session, watcherDisposables);
   246→		}
   247→
   248→		// Uncorrelated file watching: via shared `watch()`
   249→		else {
   250→			this._logService.trace(`MainThreadFileSystemEventService#$watch(): request to start watching uncorrelated (extension: ${extensionId}, path: ${uri.toString(true)}, recursive: ${opts.recursive}, session: ${session}, excludes: ${JSON.stringify(opts.excludes)}, includes: ${JSON.stringify(opts.includes)})`);
   251→
   252→			const subscription = this._fileService.watch(uri, opts);
   253→			this._watches.set(session, subscription);
   254→		}
   255→	}
   256→
   257→	$unwatch(session: number): void {
   258→		if (this._watches.has(session)) {
   259→			this._logService.trace(`MainThreadFileSystemEventService#$unwatch(): request to stop watching (session: ${session})`);
   260→			this._watches.deleteAndDispose(session);
   261→		}
   262→	}
   263→
   264→	dispose(): void {
   265→		this._listener.dispose();
   266→		this._watches.dispose();
   267→	}
   268→}
