   111→	provideCodeActions(document: TextDocument, range: Range | Selection): CodeAction[] {
   112→		const codeActions: CodeAction[] = [];
   113→		const diagnostics = this.diagnosticsManager.getDiagnostics(document.uri);
   114→		const wrapAllLinesCodeAction = this.getWrapAllLinesCodeAction(document, diagnostics);
   115→
   116→		for (const diagnostic of diagnostics) {
   117→			if (!diagnostic.range.contains(range)) {
   118→				continue;
   119→			}
   120→
   121→			switch (diagnostic.code) {
   122→				case DiagnosticCodes.empty_message: {
   123→					const workspaceEdit = new WorkspaceEdit();
   124→					workspaceEdit.delete(document.uri, diagnostic.range);
   125→
   126→					const codeAction = new CodeAction(l10n.t('Clear whitespace characters'), CodeActionKind.QuickFix);
   127→					codeAction.diagnostics = [diagnostic];
   128→					codeAction.edit = workspaceEdit;
   129→					codeActions.push(codeAction);
   130→
   131→					break;
   132→				}
   133→				case DiagnosticCodes.line_length: {
   134→					const workspaceEdit = this.getWrapLineWorkspaceEdit(document, diagnostic.range);
   135→
   136→					const codeAction = new CodeAction(l10n.t('Hard wrap line'), CodeActionKind.QuickFix);
   137→					codeAction.diagnostics = [diagnostic];
   138→					codeAction.edit = workspaceEdit;
   139→					codeActions.push(codeAction);
   140→
   141→					if (wrapAllLinesCodeAction) {
   142→						wrapAllLinesCodeAction.diagnostics = [diagnostic];
   143→						codeActions.push(wrapAllLinesCodeAction);
   144→					}
   145→
   146→					break;
   147→				}
   148→			}
   149→		}
   150→
   151→		return codeActions;
   152→	}
   153→
   154→	private getWrapLineWorkspaceEdit(document: TextDocument, range: Range): WorkspaceEdit {
   155→		const lineSegments = this.wrapTextDocumentLine(document, range.start.line);
   156→
   157→		const workspaceEdit = new WorkspaceEdit();
   158→		workspaceEdit.replace(document.uri, range, lineSegments.join('\n'));
   159→
   160→		return workspaceEdit;
   161→	}
